export async function chargeViaIntent(orderId: string, amountCents: number) {
  void orderId;
  return callProvider("/payment_intents", { amountCents }); // no idempotency key
}

export async function chargeViaLegacy(orderId: string, amountCents: number) {
  const idempotencyKey = `order-${orderId}`;
  return callProvider("/charges", { amountCents }, { idempotencyKey });
}

export async function checkout(orderId: string, amountCents: number, useIntents: boolean) {
  const charge = useIntents ? chargeViaIntent : chargeViaLegacy;
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      return await charge(orderId, amountCents);
    } catch {
      // transient failure — retry
    }
  }
}

